#!/usr/bin/env node
/**
 * Generate Excalidraw compressed JSON for architecture diagrams
 * This script creates valid Excalidraw files with proper compressed JSON data
 */

const zlib = require('zlib');

// Helper to compress JSON to Excalidraw format
function compressExcalidrawJSON(elements) {
    const jsonStr = JSON.stringify({
        type: "excalidraw",
        version: 2,
        source: "https://excalidraw.com",
        elements: elements,
        appState: {
            gridSize: null,
            viewBackgroundColor: "#ffffff"
        }
    });
    const compressed = zlib.deflateRawSync(Buffer.from(jsonStr));
    return compressed.toString('base64');
}

// Color palette
const colors = {
    diamond: { stroke: "#c92a2a", background: "#ffc9c9" },      // Red for central
    blue: { stroke: "#1864ab", background: "#a5d8ff" },         // Blue
    green: { stroke: "#2b8a3e", background: "#b2f2bb" },        // Green
    orange: { stroke: "#d9480f", background: "#ffd8a8" },       // Orange
    purple: { stroke: "#5f3dc4", background: "#d0bfff" },       // Purple
    gray: { stroke: "#495057", background: "#e9ecef" },         // Gray
    yellow: { stroke: "#f08c00", background: "#ffec99" },       // Yellow
    text: "#1e1e1e",
    redText: "#e03131"
};

// Helper to create rectangle
function createRect(id, x, y, width, height, text, colorSet, options = {}) {
    return {
        id: id,
        type: "rectangle",
        x: x,
        y: y,
        width: width,
        height: height,
        angle: 0,
        strokeColor: colorSet.stroke,
        backgroundColor: colorSet.background,
        fillStyle: "solid",
        strokeWidth: 2,
        strokeStyle: "solid",
        roughness: 1,
        opacity: 100,
        groupIds: [],
        frameId: null,
        roundness: { type: 3, value: 8 },
        seed: Math.floor(Math.random() * 100000),
        version: 1,
        versionNonce: Math.floor(Math.random() * 100000),
        isDeleted: false,
        boundElements: [{ type: "text", id: `${id}_text` }],
        updated: Date.now(),
        link: null,
        locked: false,
        ...options
    };
}

// Helper to create diamond
function createDiamond(id, x, y, width, height, text, colorSet) {
    return {
        id: id,
        type: "diamond",
        x: x,
        y: y,
        width: width,
        height: height,
        angle: 0,
        strokeColor: colorSet.stroke,
        backgroundColor: colorSet.background,
        fillStyle: "solid",
        strokeWidth: 2,
        strokeStyle: "solid",
        roughness: 1,
        opacity: 100,
        groupIds: [],
        frameId: null,
        roundness: { type: 3, value: 8 },
        seed: Math.floor(Math.random() * 100000),
        version: 1,
        versionNonce: Math.floor(Math.random() * 100000),
        isDeleted: false,
        boundElements: [{ type: "text", id: `${id}_text` }],
        updated: Date.now(),
        link: null,
        locked: false
    };
}

// Helper to create ellipse
function createEllipse(id, x, y, width, height, text, colorSet) {
    return {
        id: id,
        type: "ellipse",
        x: x,
        y: y,
        width: width,
        height: height,
        angle: 0,
        strokeColor: colorSet.stroke,
        backgroundColor: colorSet.background,
        fillStyle: "solid",
        strokeWidth: 2,
        strokeStyle: "solid",
        roughness: 1,
        opacity: 100,
        groupIds: [],
        frameId: null,
        seed: Math.floor(Math.random() * 100000),
        version: 1,
        versionNonce: Math.floor(Math.random() * 100000),
        isDeleted: false,
        boundElements: [{ type: "text", id: `${id}_text` }],
        updated: Date.now(),
        link: null,
        locked: false
    };
}

// Helper to create text
function createText(id, x, y, text, fontSize = 16, textColor = colors.text, width = 200) {
    return {
        id: id,
        type: "text",
        x: x,
        y: y,
        width: width,
        height: fontSize * 1.25,
        angle: 0,
        strokeColor: textColor,
        backgroundColor: "transparent",
        fillStyle: "solid",
        strokeWidth: 1,
        strokeStyle: "solid",
        roughness: 0,
        opacity: 100,
        groupIds: [],
        frameId: null,
        roundness: null,
        seed: Math.floor(Math.random() * 100000),
        version: 1,
        versionNonce: Math.floor(Math.random() * 100000),
        isDeleted: false,
        boundElements: null,
        updated: Date.now(),
        link: null,
        locked: false,
        text: text,
        fontSize: fontSize,
        fontFamily: 2, // Virgil hand-drawn font
        textAlign: "center",
        verticalAlign: "middle",
        containerId: id.replace('_text', ''),
        originalText: text,
        lineHeight: 1.25,
        baseline: 18
    };
}

// Helper to create arrow
function createArrow(id, x1, y1, x2, y2, label = "") {
    const elements = [{
        id: id,
        type: "arrow",
        x: x1,
        y: y1,
        width: x2 - x1,
        height: y2 - y1,
        angle: 0,
        strokeColor: "#495057",
        backgroundColor: "transparent",
        fillStyle: "solid",
        strokeWidth: 2,
        strokeStyle: "solid",
        roughness: 1,
        opacity: 100,
        groupIds: [],
        frameId: null,
        roundness: { type: 2 },
        seed: Math.floor(Math.random() * 100000),
        version: 1,
        versionNonce: Math.floor(Math.random() * 100000),
        isDeleted: false,
        boundElements: label ? [{ type: "text", id: `${id}_label` }] : [],
        updated: Date.now(),
        link: null,
        locked: false,
        startBinding: null,
        endBinding: null,
        lastCommittedPoint: null,
        startArrowhead: null,
        endArrowhead: "arrow",
        points: [[0, 0], [x2 - x1, y2 - y1]]
    }];

    if (label) {
        elements.push({
            id: `${id}_label`,
            type: "text",
            x: (x1 + x2) / 2 - 40,
            y: (y1 + y2) / 2 - 10,
            width: 80,
            height: 20,
            angle: 0,
            strokeColor: colors.text,
            backgroundColor: "transparent",
            fillStyle: "solid",
            strokeWidth: 1,
            strokeStyle: "solid",
            roughness: 0,
            opacity: 100,
            groupIds: [],
            frameId: null,
            roundness: null,
            seed: Math.floor(Math.random() * 100000),
            version: 1,
            versionNonce: Math.floor(Math.random() * 100000),
            isDeleted: false,
            boundElements: null,
            updated: Date.now(),
            link: null,
            locked: false,
            text: label,
            fontSize: 12,
            fontFamily: 2,
            textAlign: "center",
            verticalAlign: "middle",
            containerId: id,
            originalText: label,
            lineHeight: 1.25,
            baseline: 14
        });
    }

    return elements;
}

// ==================== Diagram 1: Service Topology ====================
function generateDiagram1() {
    const elements = [];
    let id = 0;

    // Central Diamond: Agent Framework
    const centerX = 500, centerY = 300;
    elements.push(createDiamond(`el${++id}`, centerX - 100, centerY - 80, 200, 160, "Agent Framework", colors.diamond));
    elements.push(createText(`el${id}_text`, centerX - 80, centerY - 40, "Agent Framework\n(task execution,\nmulti-agent\norchestration)", 14, colors.text, 160));

    // Left: Agent-TES
    elements.push(createRect(`el${++id}`, 100, 280, 180, 120, "Agent-TES", colors.blue));
    elements.push(createText(`el${id}_text`, 120, 300, "Agent-TES\n(Telemetry &\nEvidence Service)", 13, colors.text, 140));

    // Sub-components for Agent-TES
    elements.push(createRect(`el${++id}`, 120, 420, 50, 40, "eBPF", colors.gray));
    elements.push(createText(`el${id}_text`, 125, 430, "eBPF", 11, colors.text, 40));

    elements.push(createRect(`el${++id}`, 180, 420, 50, 40, "Sidecar", colors.gray));
    elements.push(createText(`el${id}_text`, 185, 430, "Sidecar", 11, colors.text, 40));

    elements.push(createRect(`el${++id}`, 120, 470, 110, 40, "Bytecode", colors.gray));
    elements.push(createText(`el${id}_text`, 125, 480, "Bytecode Inst.", 11, colors.text, 100));

    // Bottom: Agentic Memory (3 layers)
    elements.push(createRect(`el${++id}`, 410, 520, 180, 140, "Agentic Memory", colors.green));
    elements.push(createText(`el${id}_text`, 430, 540, "Agentic Memory\n(3 Layers)", 14, colors.text, 140));

    // Memory layers
    elements.push(createRect(`el${++id}`, 430, 600, 140, 30, "Working", colors.yellow));
    elements.push(createText(`el${id}_text`, 435, 605, "Working Memory", 11, colors.text, 130));

    elements.push(createRect(`el${++id}`, 430, 640, 140, 30, "Procedural", colors.yellow));
    elements.push(createText(`el${id}_text`, 435, 645, "Procedural Memory", 11, colors.text, 130));

    elements.push(createRect(`el${++id}`, 430, 680, 140, 30, "Semantic", colors.yellow));
    elements.push(createText(`el${id}_text`, 435, 685, "Semantic Memory", 11, colors.text, 130));

    // Right: Skill-MDS
    elements.push(createRect(`el${++id}`, 720, 280, 180, 120, "Skill-MDS", colors.purple));
    elements.push(createText(`el${id}_text`, 740, 300, "Skill-MDS\n(Skill Mining &\nDiscovery)", 13, colors.text, 140));

    // Arrows - Data flows
    // tracing from Agent-TES to Agent Framework
    elements.push(...createArrow(`el${++id}`, 280, 340, 400, 340, "tracing"));

    // memory IO between Agent Framework and Agentic Memory
    elements.push(...createArrow(`el${++id}`, 500, 380, 500, 520, "memory IO"));

    // applying from Agent Framework to Skill-MDS
    elements.push(...createArrow(`el${++id}`, 600, 340, 720, 340, "applying"));

    // streaming data pipeline from Agent-TES to Skill-MDS
    elements.push(...createArrow(`el${++id}`, 280, 400, 720, 400, "streaming pipeline"));

    // skill gen pipeline from Skill-MDS (feedback loop visual)
    elements.push(...createArrow(`el${++id}`, 720, 280, 600, 220, "skill gen"));

    // business documents to Semantic Memory
    elements.push(...createArrow(`el${++id}`, 300, 700, 430, 700, "documents"));

    return compressExcalidrawJSON(elements);
}

// ==================== Diagram 2: Data Flow & Storage Layers ====================
function generateDiagram2() {
    const elements = [];
    let id = 0;

    // Layer 5: Multi-Agent System
    elements.push(createRect(`el${++id}`, 200, 50, 600, 100, "Layer 5", colors.diamond));
    elements.push(createText(`el${id}_text`, 250, 70, "Layer 5: Multi-Agent System\nCoT, Interaction Data, Evidence, Decision Traces", 14, colors.text, 500));

    // Layer 4: Memory Lake
    elements.push(createRect(`el${++id}`, 200, 180, 600, 100, "Layer 4", colors.blue));
    elements.push(createText(`el${id}_text`, 250, 200, "Layer 4: Memory Lake\nTree, Graph, Time Series, Vector", 14, colors.text, 500));

    // Layer 3: Multimodal Lake
    elements.push(createRect(`el${++id}`, 200, 310, 600, 100, "Layer 3", colors.green));
    elements.push(createText(`el${id}_text`, 250, 330, "Layer 3: Multimodal Lake\nCoT, Docs, Video, Img, Table", 14, colors.text, 500));

    // Layer 2: Data Sources
    elements.push(createRect(`el${++id}`, 200, 440, 600, 100, "Layer 2", colors.gray));
    elements.push(createText(`el${id}_text`, 250, 460, "Layer 2: Data Sources\nBusiness Systems, Trace System", 14, colors.text, 500));

    // Layer 1: Knowledge Engineering
    elements.push(createRect(`el${++id}`, 200, 570, 600, 120, "Layer 1", colors.orange));
    elements.push(createText(`el${id}_text`, 250, 590, "Layer 1: Knowledge Engineering\nAgentic Memory, Skill Gen, RL Dataset, Chain of Evidence", 14, colors.text, 500));

    // Red text note
    elements.push(createText(`el${++id}`, 150, 720, "搜索才是记忆的核心，记忆的构建是为了支持有效的搜索", 18, colors.redText, 700));

    // Arrows between layers
    elements.push(...createArrow(`el${++id}`, 500, 150, 500, 180, ""));
    elements.push(...createArrow(`el${++id}`, 500, 280, 500, 310, ""));
    elements.push(...createArrow(`el${++id}`, 500, 410, 500, 440, ""));
    elements.push(...createArrow(`el${++id}`, 500, 540, 500, 570, ""));

    // Upward arrow from Layer 1 to Layer 4
    elements.push(...createArrow(`el${++id}`, 650, 570, 650, 280, "feedback"));

    return compressExcalidrawJSON(elements);
}

// ==================== Diagram 3: Semantic Memory Internal Structure ====================
function generateDiagram3() {
    const elements = [];
    let id = 0;

    // Layer 5 (orange): Section Summary Level 2
    elements.push(createRect(`el${++id}`, 300, 50, 400, 70, "Layer 5", colors.orange));
    elements.push(createText(`el${id}_text`, 350, 65, "Layer 5: Section Summary Level 2\n(cross-section summary)", 13, colors.text, 300));

    // Layer 4 (blue): Section Summary Level 1
    elements.push(createRect(`el${++id}`, 200, 150, 250, 80, "Layer 4a", colors.blue));
    elements.push(createText(`el${id}_text`, 220, 165, "Section Summary\nLevel 1 (A)", 12, colors.text, 200));

    elements.push(createRect(`el${++id}`, 550, 150, 250, 80, "Layer 4b", colors.blue));
    elements.push(createText(`el${id}_text`, 570, 165, "Section Summary\nLevel 1 (B)", 12, colors.text, 200));

    // Layer 3 (green): Content Blocks (RAG layer)
    elements.push(createRect(`el${++id}`, 150, 280, 120, 80, "Block1", colors.green));
    elements.push(createText(`el${id}_text`, 160, 300, "Raw Text", 12, colors.text, 100));

    elements.push(createRect(`el${++id}`, 290, 280, 120, 80, "Block2", colors.green));
    elements.push(createText(`el${id}_text`, 300, 300, "Table", 12, colors.text, 100));

    elements.push(createRect(`el${++id}`, 430, 280, 120, 80, "Block3", colors.green));
    elements.push(createText(`el${id}_text`, 440, 300, "Image", 12, colors.text, 100));

    elements.push(createRect(`el${++id}`, 570, 280, 120, 80, "Block4", colors.green));
    elements.push(createText(`el${id}_text`, 580, 300, "Text", 12, colors.text, 100));

    elements.push(createRect(`el${++id}`, 710, 280, 120, 80, "Block5", colors.green));
    elements.push(createText(`el${id}_text`, 720, 300, "Code", 12, colors.text, 100));

    // Layer 2 (blue ellipse): Phrase Nodes
    elements.push(createEllipse(`el${++id}`, 250, 450, 100, 60, "Phrase A", colors.blue));
    elements.push(createText(`el${id}_text`, 280, 470, "Phrase A", 12, colors.text, 60));

    elements.push(createEllipse(`el${++id}`, 450, 450, 100, 60, "Phrase B", colors.blue));
    elements.push(createText(`el${id}_text`, 480, 470, "Phrase B", 12, colors.text, 60));

    elements.push(createEllipse(`el${++id}`, 650, 450, 100, 60, "Phrase C", colors.blue));
    elements.push(createText(`el${id}_text`, 680, 470, "Phrase C", 12, colors.text, 60));

    // Layer 1 (orange ellipse): Community Node Summaries
    elements.push(createEllipse(`el${++id}`, 350, 600, 140, 80, "Community 1", colors.orange));
    elements.push(createText(`el${id}_text`, 380, 620, "Community 1", 13, colors.text, 100));

    elements.push(createEllipse(`el${++id}`, 600, 600, 140, 80, "Community 2", colors.orange));
    elements.push(createText(`el${id}_text`, 630, 620, "Community 2", 13, colors.text, 100));

    // Side: Vector Clustering
    elements.push(createRect(`el${++id}`, 50, 450, 120, 150, "Clustering", colors.purple));
    elements.push(createText(`el${id}_text`, 60, 480, "Vector\nClustering\n\ncluster 1..n", 12, colors.text, 100));

    // Arrows - Context Edges
    elements.push(...createArrow(`el${++id}`, 210, 360, 280, 420, "Context"));
    elements.push(...createArrow(`el${++id}`, 350, 360, 480, 420, "Context"));
    elements.push(...createArrow(`el${++id}`, 490, 360, 520, 420, "Context"));

    // Relation edges between phrases
    elements.push(...createArrow(`el${++id}`, 350, 480, 400, 480, "Relation"));
    elements.push(...createArrow(`el${++id}`, 550, 480, 600, 480, "Synonym"));

    // Belongs_to edges
    elements.push(...createArrow(`el${++id}`, 300, 510, 380, 560, "belongs"));
    elements.push(...createArrow(`el${++id}`, 600, 510, 620, 560, "belongs"));

    // Upward arrows
    elements.push(...createArrow(`el${++id}`, 325, 230, 400, 120, ""));
    elements.push(...createArrow(`el${++id}`, 675, 230, 600, 120, ""));
    elements.push(...createArrow(`el${++id}`, 400, 120, 500, 120, ""));

    // Clustering arrows
    elements.push(...createArrow(`el${++id}`, 170, 500, 250, 480, ""));
    elements.push(...createArrow(`el${++id}`, 170, 520, 450, 480, ""));

    return compressExcalidrawJSON(elements);
}

// Generate all diagrams
const diagram1 = generateDiagram1();
const diagram2 = generateDiagram2();
const diagram3 = generateDiagram3();

console.log("=== DIAGRAM 1: Service Topology ===");
console.log(diagram1);
console.log("\n=== DIAGRAM 2: Data Flow ===");
console.log(diagram2);
console.log("\n=== DIAGRAM 3: Semantic Memory ===");
console.log(diagram3);
